<script setup lang="ts">
definePageMeta({layout:'default'})
const supabase=useSupabaseClient<any>(),data=ref<any>(),loading=ref(true),busy=ref(false),error=ref(''),message=ref(''),view=ref('team')
const setup=reactive({mode:'exception_only',jurisdictions:'US-CA, US-DE',currency:'USD',approval_amount:10000})
const recipeKey=ref('employee_onboarding'),recipeInput=reactive<Record<string,string>>({}),authority=reactive({subject_ref:'agent:treasury_chief',scopes:'prepare_payment,reconcile_accounts',jurisdictions:'US-CA',amount_limit:10000,currency:'USD',valid_until:''}),simulation=reactive({objective:'Find the simplest resilient operating structure',jurisdictions:'US-DE, US-CA',entity_types:'single_entity,parent_subsidiary',revenue:0,employees:0,regulated:false}),negotiation=reactive({counterparty:'',annual_value:100000,margin:.5,churn_risk:.1,dispute_risk:.05,operational_cost:5000})
const inputResponses=reactive<Record<string,Record<string,string>>>({})
const currentRecipe=computed(()=>data.value?.recipes?.find((x:any)=>x.key===recipeKey.value))
const connected=computed(()=>new Set((data.value?.connected||[]).map((x:any)=>x.provider)))
const tone=(state:string)=>['active','completed','resolved','verified','answered'].includes(state)?'bg-emerald-50 text-emerald-700':['approval_required','attention','waiting_input','proposed','predicted','prepared'].includes(state)?'bg-amber-50 text-amber-700':['blocked','failed','revoked'].includes(state)?'bg-red-50 text-red-700':'bg-gray-100 text-gray-600'
const label=(value:string)=>String(value||'').replaceAll('_',' ').replace(/\b\w/g,x=>x.toUpperCase())
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(options.headers||{}),...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){loading.value=true;error.value='';try{data.value=await authed('/api/business/executive-team');for(const req of data.value?.inputs||[])inputResponses[req.id]||={}}catch(e:any){error.value=e?.data?.message||e?.message||'The virtual executive team could not load.'}finally{loading.value=false}}
async function act(action:string,values:any={}){busy.value=true;error.value='';message.value='';try{const result:any=await authed('/api/business/executive-team/action',{method:'POST',body:{action,values}});message.value=result.needs_input?'Madeus requested only the missing minimum input.':action==='provision_team'?`${result.agents} functional agents activated under one shared policy.`:action==='run_recipe'?'Exactly-once workflow prepared; external effects are on the approval rail.':`${label(action)} completed and receipted.`;await load();return result}catch(e:any){error.value=e?.data?.message||e?.message||'The operation could not be completed.'}finally{busy.value=false}}
function provision(){return act('provision_team',{...setup,jurisdictions:setup.jurisdictions.split(',').map(x=>x.trim()).filter(Boolean)})}
function runRecipe(){return act('run_recipe',{recipe:recipeKey.value,input:{...recipeInput}})}
function issueAuthority(){return act('issue_authority',{subject_type:'agent',subject_ref:authority.subject_ref,credential_type:'bounded_execution',scopes:authority.scopes.split(',').map(x=>x.trim()).filter(Boolean),jurisdictions:authority.jurisdictions.split(',').map(x=>x.trim()).filter(Boolean),amount_limit:authority.amount_limit,currency:authority.currency,valid_until:authority.valid_until||null})}
function simulate(){return act('simulate_structure',{...simulation,jurisdictions:simulation.jurisdictions.split(',').map(x=>x.trim()).filter(Boolean),entity_types:simulation.entity_types.split(',').map(x=>x.trim()).filter(Boolean)})}
function simulateNegotiation(){return act('simulate_negotiation_value',{...negotiation})}
function answer(req:any){return act('answer_input',{request_id:req.id,response:inputResponses[req.id]||{}})}
watch(currentRecipe,r=>{for(const field of r?.required||[])if(!(field in recipeInput))recipeInput[field]=''},{immediate:true})
onMounted(load)
</script>
<template><main class="min-h-full bg-[#f7f8f5] text-[#171817]">
 <header class="border-b bg-[radial-gradient(circle_at_84%_8%,#cffafe,transparent_27%),radial-gradient(circle_at_62%_75%,#e0e7ff,transparent_28%),linear-gradient(145deg,#fff,#edf1ec)]"><div class="mx-auto max-w-[1320px] px-6 py-12"><div class="flex items-center justify-between"><NuxtLink to="/business/autonomy" class="text-[10px] text-gray-500">← Autonomous Operations</NuxtLink><span class="rounded-full border bg-white/70 px-3 py-1 text-[9px] text-cyan-800">Policy IR · sagas · authority · evidence</span></div><div class="mt-8 grid gap-8 lg:grid-cols-[1fr_380px]"><div><span class="text-[10px] font-bold uppercase tracking-[.16em] text-cyan-800">Virtual executive team</span><h1 class="mt-3 text-5xl font-semibold tracking-[-.055em] md:text-7xl">Every function running.<br><em class="not-italic text-gray-500">Only decisions reach you.</em></h1><p class="mt-5 max-w-3xl text-sm leading-7 text-gray-600">Configure once, prompt when needed, and let twelve agentic functional leaders predict, prepare, reconcile, and complete governed work across people, payroll, banking, tax, legal, compliance, accounting, security, procurement, revenue, risk, and operations.</p></div><aside class="rounded-2xl border bg-gray-950 p-5 text-white"><span class="text-[9px] uppercase tracking-wider text-cyan-300">One-click operating posture</span><h2 class="mt-2 text-xl font-semibold">Exception-only by default.</h2><p class="mt-2 text-[10px] leading-5 text-gray-400">Internal reversible work executes automatically. Anything binding, irreversible, regulated, monetary, or employment-consequential requires a scoped credential and explicit approval.</p><button :disabled="busy" class="mt-5 w-full rounded-lg bg-white px-4 py-3 text-[10px] font-semibold text-gray-950 disabled:opacity-40" @click="provision">{{data?.summary?.agents_active?'Recompile team policy':'Activate all 12 agents'}}</button></aside></div></div></header>
 <div class="mx-auto max-w-[1320px] space-y-8 px-6 py-8"><p v-if="error" role="alert" class="rounded-xl border border-red-200 bg-red-50 p-3 text-xs text-red-700">{{error}}</p><p v-if="message" role="status" class="rounded-xl border border-emerald-200 bg-emerald-50 p-3 text-xs text-emerald-700">{{message}}</p>
 <section v-if="data" class="grid overflow-hidden rounded-2xl border bg-white sm:grid-cols-2 lg:grid-cols-5"><article v-for="x in [{l:'Agents active',v:data.summary.agents_active},{l:'Workflows running',v:data.summary.sagas_running},{l:'True exceptions',v:data.summary.exceptions},{l:'Predicted work',v:data.summary.predictions},{l:'Needs your input',v:data.summary.inputs}]" :key="x.l" class="border-b p-5 sm:border-r lg:border-b-0"><span class="text-[8px] uppercase tracking-wider text-gray-400">{{x.l}}</span><b class="mt-2 block text-3xl">{{x.v}}</b></article></section>
 <nav class="flex gap-2 overflow-x-auto rounded-xl border bg-white p-2"><button v-for="x in [{k:'team',l:'Functional team'},{k:'run',l:'Run anything'},{k:'attention',l:'Needs you'},{k:'authority',l:'Authority'},{k:'architecture',l:'Entity simulator'}]" :key="x.k" class="whitespace-nowrap rounded-lg px-4 py-2 text-[9px]" :class="view===x.k?'bg-gray-950 text-white':'text-gray-500'" @click="view=x.k">{{x.l}}</button><span class="ml-auto hidden items-center gap-2 px-3 text-[8px] text-gray-400 md:flex"><i class="h-2 w-2 rounded-full bg-emerald-500"/>{{connected.size}} providers connected</span></nav>
 <section v-if="view==='team'" class="grid gap-3 md:grid-cols-2 lg:grid-cols-3"><form class="flex min-h-64 flex-col rounded-2xl border border-cyan-200 bg-cyan-50 p-5" @submit.prevent="provision"><span class="text-[8px] font-bold uppercase tracking-wider text-cyan-800">Shared operating policy</span><h2 class="mt-3 text-xl font-semibold">Configure once</h2><label class="mt-3 text-[8px] font-semibold">Autonomy<select v-model="setup.mode" class="mt-1 w-full rounded-lg border bg-white p-2 text-[10px]"><option value="observe">Observe</option><option value="prepare">Prepare</option><option value="execute_reversible">Execute reversible</option><option value="exception_only">Exception only</option></select></label><div class="mt-2 grid grid-cols-2 gap-2"><label class="text-[8px] font-semibold">Jurisdictions<input v-model="setup.jurisdictions" class="mt-1 w-full rounded-lg border bg-white p-2 text-[10px]"></label><label class="text-[8px] font-semibold">Approval threshold<input v-model.number="setup.approval_amount" type="number" min="0" class="mt-1 w-full rounded-lg border bg-white p-2 text-[10px]"></label></div><button :disabled="busy" class="mt-auto rounded-lg bg-cyan-950 px-3 py-2 text-[9px] text-white">Compile policy + activate</button></form><article v-for="agent in data?.definitions||[]" :key="agent.key" class="flex min-h-64 flex-col rounded-2xl border bg-white p-5"><div class="flex justify-between"><span class="rounded-full bg-cyan-50 px-2 py-1 text-[8px] uppercase text-cyan-800">{{agent.domain}}</span><i class="h-2 w-2 rounded-full" :class="data?.agents?.some((x:any)=>x.agent_key===agent.key&&x.status==='active')?'bg-emerald-500':'bg-gray-300'"/></div><h2 class="mt-5 text-xl font-semibold">{{agent.name}}</h2><p class="mt-2 text-[10px] leading-5 text-gray-500">{{agent.objective}}</p><div class="mt-auto border-t pt-4"><span class="text-[8px] uppercase text-gray-400">Runs on</span><p class="mt-1 text-[8px] leading-4 text-gray-500">{{agent.triggers.slice(0,4).map(label).join(' · ')}}</p></div></article></section>
 <section v-else-if="view==='run'" class="grid gap-5 lg:grid-cols-[430px_minmax(0,1fr)]"><form class="rounded-2xl border bg-white p-5" @submit.prevent="runRecipe"><span class="text-[9px] font-bold uppercase tracking-wider text-cyan-800">Natural input → governed execution</span><h2 class="mt-2 text-2xl font-semibold">Run a complete business process</h2><label class="mt-5 block text-[9px] font-semibold">Workflow<select v-model="recipeKey" class="mt-1 w-full rounded-lg border p-2 text-xs"><option v-for="recipe in data?.recipes||[]" :key="recipe.key" :value="recipe.key">{{label(recipe.key)}}</option></select></label><p class="mt-2 rounded-lg bg-gray-50 p-3 text-[9px] leading-4 text-gray-500">{{currentRecipe?.goal}}</p><div class="mt-4 grid gap-3 sm:grid-cols-2"><label v-for="field in currentRecipe?.required||[]" :key="field" class="text-[9px] font-semibold">{{label(field)}}<input v-model="recipeInput[field]" :type="field.includes('date')?'date':'text'" class="mt-1 w-full rounded-lg border p-2 text-xs" :placeholder="label(field)"></label></div><button :disabled="busy" class="mt-5 w-full rounded-lg bg-gray-950 px-4 py-3 text-[10px] font-semibold text-white disabled:opacity-40">Prepare and run safely</button><p class="mt-2 text-[8px] leading-4 text-gray-400">Missing facts create a concise input request. Connected providers receive only the minimum scopes. External effects move to approvals.</p></form><article class="overflow-hidden rounded-2xl border bg-white"><header class="flex items-center justify-between border-b p-5"><div><span class="text-[9px] uppercase text-cyan-800">Saga timeline</span><h2 class="mt-1 text-xl font-semibold">Exactly once, with compensation</h2></div><button :disabled="busy" class="rounded-lg border px-3 py-2 text-[8px]" @click="act('run_reconciliation')">Reconcile evidence</button></header><div v-if="!data?.sagas?.length" class="p-16 text-center text-xs text-gray-400">Run a workflow to see every step, approval, connector, and receipt.</div><section v-for="saga in data?.sagas||[]" :key="saga.id" class="border-b p-4"><div class="flex items-center justify-between"><div><b class="text-[11px]">{{saga.goal}}</b><p class="mt-1 text-[8px] text-gray-400">{{label(saga.saga_type)}} · {{saga.id.slice(0,8)}}</p></div><span class="rounded-full px-2 py-1 text-[8px]" :class="tone(saga.state)">{{label(saga.state)}}</span></div><div class="mt-3 flex gap-1"><i v-for="step in data.steps.filter((x:any)=>x.saga_id===saga.id)" :key="step.id" class="h-1.5 flex-1 rounded-full" :class="step.state==='completed'?'bg-emerald-500':step.state==='approval_required'?'bg-amber-400':step.state==='blocked'?'bg-red-500':'bg-gray-200'" :title="`${label(step.operation)} · ${label(step.state)}`"/></div></section></article></section>
 <section v-else-if="view==='attention'" class="grid gap-5 lg:grid-cols-2"><article class="rounded-2xl border bg-white p-5"><header class="flex items-end justify-between"><div><span class="text-[9px] uppercase text-cyan-800">Predictive work</span><h2 class="mt-1 text-xl font-semibold">Handle it before it is urgent</h2></div><button :disabled="busy" class="rounded-lg bg-gray-950 px-3 py-2 text-[9px] text-white" @click="act('predict_work')">Predict now</button></header><p v-if="!data?.predictions?.length" class="py-12 text-center text-[10px] text-gray-400">No predictions yet.</p><div v-for="p in data?.predictions||[]" :key="p.id" class="mt-3 rounded-xl border p-3"><div class="flex justify-between"><b class="text-[10px]">{{p.title}}</b><span class="rounded-full px-2 py-1 text-[8px]" :class="tone(p.state)">{{Math.round(p.confidence*100)}}%</span></div><p class="mt-1 text-[8px] text-gray-400">{{label(p.agent_key)}} · {{label(p.prediction_type)}}</p></div></article><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Minimum human input</span><h2 class="mt-1 text-xl font-semibold">Short questions, complete context</h2><p v-if="!data?.inputs?.filter((x:any)=>x.state==='open').length" class="py-12 text-center text-[10px] text-gray-400">Madeus has everything it needs.</p><form v-for="req in data?.inputs?.filter((x:any)=>x.state==='open')||[]" :key="req.id" class="mt-3 rounded-xl border border-amber-200 bg-amber-50 p-4" @submit.prevent="answer(req)"><b class="text-[10px]">{{req.prompt}}</b><p class="mt-1 text-[8px] text-amber-800">{{req.reason}}</p><div class="mt-3 grid gap-2 sm:grid-cols-2"><label v-for="(_,field) in req.input_schema" :key="field" class="text-[8px] font-semibold">{{label(String(field))}}<input v-model="inputResponses[req.id][String(field)]" class="mt-1 w-full rounded-lg border p-2 text-[10px]"></label></div><button class="mt-3 rounded-lg bg-amber-900 px-3 py-2 text-[9px] text-white">Continue workflow</button></form></article></section>
 <section v-else-if="view==='authority'" class="grid gap-5 lg:grid-cols-[430px_minmax(0,1fr)]"><form class="rounded-2xl border bg-white p-5" @submit.prevent="issueAuthority"><span class="text-[9px] font-bold uppercase tracking-wider text-cyan-800">Revocable authority credential</span><h2 class="mt-2 text-2xl font-semibold">Delegate narrowly, never blindly</h2><label class="mt-4 block text-[9px] font-semibold">Agent or role<input v-model="authority.subject_ref" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="mt-3 block text-[9px] font-semibold">Allowed scopes<input v-model="authority.scopes" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><div class="mt-3 grid grid-cols-2 gap-3"><label class="text-[9px] font-semibold">Jurisdictions<input v-model="authority.jurisdictions" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="text-[9px] font-semibold">Amount limit<input v-model.number="authority.amount_limit" type="number" min="0" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="text-[9px] font-semibold">Currency<input v-model="authority.currency" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="text-[9px] font-semibold">Expires<input v-model="authority.valid_until" type="date" class="mt-1 w-full rounded-lg border p-2 text-xs"></label></div><button :disabled="busy" class="mt-5 w-full rounded-lg bg-gray-950 px-4 py-3 text-[10px] text-white">Create two-key approval</button></form><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Authority graph</span><h2 class="mt-1 text-xl font-semibold">Every power has a boundary</h2><div v-if="!data?.credentials?.length" class="p-12 text-center text-[10px] text-gray-400">No delegated authority. Agents remain prepare-only for external effects.</div><section v-for="c in data?.credentials||[]" :key="c.id" class="mt-3 rounded-xl border p-4"><div class="flex justify-between"><b class="text-[10px]">{{c.subject_ref}}</b><span class="rounded-full px-2 py-1 text-[8px]" :class="tone(c.status)">{{label(c.status)}}</span></div><p class="mt-2 text-[8px] text-gray-500">{{c.scopes.join(' · ')}}</p><p class="mt-1 text-[8px] text-gray-400">{{c.amount_limit||'No'}} {{c.currency||''}} limit · {{c.jurisdictions.join(', ')||'no jurisdiction scope'}}</p></section></article></section>
 <section v-else class="grid gap-5 lg:grid-cols-3"><form class="rounded-2xl border bg-white p-5" @submit.prevent="simulate"><span class="text-[9px] font-bold uppercase tracking-wider text-cyan-800">Entity + jurisdiction twin</span><h2 class="mt-2 text-2xl font-semibold">Simulate before structuring</h2><label class="mt-4 block text-[9px] font-semibold">Objective<textarea v-model="simulation.objective" rows="3" class="mt-1 w-full rounded-lg border p-2 text-xs"/></label><label class="mt-3 block text-[9px] font-semibold">Jurisdictions<input v-model="simulation.jurisdictions" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="mt-3 block text-[9px] font-semibold">Structures<input v-model="simulation.entity_types" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><div class="mt-3 grid grid-cols-2 gap-3"><label class="text-[9px] font-semibold">Annual revenue<input v-model.number="simulation.revenue" type="number" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><label class="text-[9px] font-semibold">Employees<input v-model.number="simulation.employees" type="number" class="mt-1 w-full rounded-lg border p-2 text-xs"></label></div><label class="mt-3 flex gap-2 text-[9px]"><input v-model="simulation.regulated" type="checkbox">Regulated activity</label><button :disabled="busy" class="mt-5 w-full rounded-lg bg-gray-950 px-4 py-3 text-[10px] text-white">Run governed simulation</button></form><form class="rounded-2xl border bg-white p-5" @submit.prevent="simulateNegotiation"><span class="text-[9px] font-bold uppercase tracking-wider text-cyan-800">Negotiation value twin</span><h2 class="mt-2 text-2xl font-semibold">Price every clause position</h2><label class="mt-4 block text-[9px] font-semibold">Counterparty<input v-model="negotiation.counterparty" class="mt-1 w-full rounded-lg border p-2 text-xs"></label><div class="mt-3 grid grid-cols-2 gap-2"><label v-for="field in ['annual_value','margin','churn_risk','dispute_risk','operational_cost']" :key="field" class="text-[8px] font-semibold">{{label(field)}}<input v-model.number="negotiation[field as keyof typeof negotiation]" type="number" step="any" class="mt-1 w-full rounded-lg border p-2 text-[10px]"></label></div><button :disabled="busy" class="mt-5 w-full rounded-lg bg-gray-950 px-4 py-3 text-[10px] text-white">Run counterfactuals</button><p class="mt-2 text-[8px] leading-4 text-gray-400">Ranks current, stronger-protection, lower-friction, and walk-away outcomes. Estimates remain assumption-bound until connected to observed causal outcomes.</p></form><article class="rounded-2xl border bg-white p-5"><span class="text-[9px] uppercase text-cyan-800">Scenario history</span><h2 class="mt-1 text-xl font-semibold">Assumptions exposed, review routed</h2><section v-for="s in data?.simulations||[]" :key="s.id" class="mt-3 rounded-xl border p-4"><div class="flex justify-between"><b class="text-[10px]">{{s.objective}}</b><span class="rounded-full bg-amber-50 px-2 py-1 text-[8px] text-amber-700">Professional review</span></div><p class="mt-2 text-[8px] text-gray-500">{{s.candidate_structures.length}} structures · {{s.authority_coverage?.missing?.length||0}} authority packs missing</p></section><section v-for="c in data?.counterfactuals||[]" :key="c.id" class="mt-3 rounded-xl border p-4"><b class="text-[10px]">{{c.subject_ref||'Contract negotiation'}}</b><p class="mt-2 text-[8px] text-gray-500">Recommended: {{c.recommendation?.name||'collect outcomes'}} · lower-confidence value {{Number(c.lower_confidence_value||0).toLocaleString()}}</p></section><p class="mt-4 text-[8px] leading-4 text-gray-400">Simulations never invent tax rates or legal conclusions. Missing primary authority is explicit and professional review remains routed.</p></article></section>
 </div></main></template>
